function initMobileDropdowns() {
const dropdowns = document.querySelectorAll('.mobile-dropdown');
dropdowns.forEach(dropdown => {
const toggleBtn = dropdown.querySelector('.mobile-dropdown-toggle');
if (toggleBtn) {
toggleBtn.addEventListener('click', (e) => {
e.preventDefault();
e.stopPropagation();
const isExpanded = toggleBtn.getAttribute('aria-expanded') === 'true';
toggleBtn.setAttribute('aria-expanded', !isExpanded);
dropdown.classList.toggle('expanded');
});
}
const links = dropdown.querySelectorAll('.mobile-dropdown-item, .mobile-dropdown-item-simple');
links.forEach(link => {
link.addEventListener('click', () => {
if (toggleBtn) {
toggleBtn.setAttribute('aria-expanded', 'false');
}
dropdown.classList.remove('expanded');
const mobileMenu = document.getElementById('mobile-menu');
const overlay = document.getElementById('mobile-overlay');
const hamburger = document.getElementById('hamburger');
if (mobileMenu) {
mobileMenu.classList.remove('open');
mobileMenu.setAttribute('aria-hidden', 'true');
}
if (overlay) overlay.classList.remove('open');
if (hamburger) hamburger.classList.remove('active');
});
});
});
}
function initHeroBadgeTyping() {
const badgeSpan = document.querySelector('.hero-badge span:last-of-type');
if (!badgeSpan) return;
const originalText = badgeSpan.textContent.trim();
if (!originalText.toLowerCase().includes('tri thức nguyên bản')) return;
badgeSpan.textContent = '';
let charIndex = 0;
const typingSpeed = 40;
function type() {
if (charIndex < originalText.length) {
badgeSpan.textContent += originalText.charAt(charIndex);
charIndex++;
setTimeout(type, typingSpeed);
}
}
type();
}
function initialize() {
initBackToTop();
initMobileDropdowns();
initMobileSliders();
initScrollDots();
initHeroBadgeTyping();
}
if (document.readyState === 'loading') {
document.addEventListener('DOMContentLoaded', initialize);
} else {
initialize();
}
window.initBackToTop = initBackToTop;
window.addEventListener('resize', () => {
initMobileSliders();
initScrollDots();
});
