function initLanguageSwitcher() {
const langBtns = document.querySelectorAll('.lang-dropdown-item, .mobile-lang-btn');
langBtns.forEach(btn => {
btn.addEventListener('click', function (e) {
if (this.tagName.toLowerCase() === 'a') {
return;
}
e.preventDefault();
const targetLang = this.getAttribute('data-lang');
if (!targetLang) return;
localStorage.setItem('lang', targetLang);
const currentLang = document.documentElement.lang || 'vi';
if (currentLang !== targetLang) {
let newPath;
const pathname = window.location.pathname;
if (targetLang === 'en') {
if (pathname.indexOf('/en/') === -1) {
const lastSlash = pathname.lastIndexOf('/');
const dir = pathname.substring(0, lastSlash + 1);
const filename = pathname.substring(lastSlash + 1);
newPath = dir + 'en/' + filename;
} else {
newPath = pathname;
}
} else {
const enIndex = pathname.indexOf('/en/');
if (enIndex !== -1) {
newPath = pathname.substring(0, enIndex) + '/' + pathname.substring(enIndex + 4);
} else {
newPath = pathname;
}
}
window.location.replace(newPath + window.location.search + window.location.hash);
}
});
});
}
function initWordPressBlog() {
const container = document.getElementById("wp-news-container");
if (!container) return;
function getWebpUrl(url) {
if (!url) return url;
if (url.includes('/wp-content/uploads/') || url.startsWith('/wp-content/')) {
return url.replace(/\.(png|jpe?g)$/i, '.webp');
}
return url;
}
function renderPosts(posts) {
if (!posts || posts.length === 0) return;
const featuredPost = posts[0];
const listPosts = posts.slice(1, 6);
const isEn = document.documentElement.lang === 'en';
const fTitle = featuredPost.title.rendered;
const fLink = featuredPost.link;
const fExcerpt = featuredPost.excerpt.rendered.replace(/<[^>]*>/g, '').substring(0, 150) + "...";
const fDate = new Date(featuredPost.date).toLocaleDateString(isEn ? 'en-US' : 'vi-VN', {
day: '2-digit',
month: isEn ? 'short' : '2-digit'
});
const fThumb = getWebpUrl(featuredPost.featured_image_url || 'https://ideas.edu.vn/wp-content/uploads/2025/07/ideas_side2.webp');
let html = `
<div class="news-featured">
<a href="${fLink}" target="_blank" class="featured-card">
<div class="thumb">
<img src="${fThumb}" alt="${fTitle}" loading="lazy">
<span class="date-badge">${fDate}</span>
</div>
<div class="content">
<h3>${fTitle}</h3>
<p>${fExcerpt}</p>
<span class="read-more">${isEn ? 'Read More' : 'Đọc tiếp'} <svg class="svg-icon fa-arrow-right fa-solid" viewBox="0 0 448 512" width="16" height="16" fill="currentColor" xmlns="http://www.w3.org/2000/svg"><path d="M438.6 278.6c12.5-12.5 12.5-32.8 0-45.3l-160-160c-12.5-12.5-32.8-12.5-45.3 0s-12.5 32.8 0 45.3L338.8 224 32 224c-17.7 0-32 14.3-32 32s14.3 32 32 32l306.7 0L233.4 393.4c-12.5 12.5-12.5 32.8 0 45.3s32.8 12.5 45.3 0l160-160z"/></svg></span>
</div>
</a>
</div>
<div class="news-list">
`;
listPosts.forEach(post => {
const lTitle = post.title.rendered;
const lLink = post.link;
const lDate = new Date(post.date).toLocaleDateString(isEn ? 'en-US' : 'vi-VN', {
day: '2-digit',
month: isEn ? 'short' : '2-digit',
year: 'numeric'
});
const lThumb = getWebpUrl(post.featured_image_url || 'https://ideas.edu.vn/wp-content/uploads/2025/07/ideas_side2.webp');
html += `
<a href="${lLink}" target="_blank" class="news-item">
<div class="item-thumb">
<img src="${lThumb}" alt="${lTitle}" loading="lazy">
</div>
<div class="item-info">
<h4>${lTitle}</h4>
<span class="item-date">${lDate}</span>
</div>
</a>
`;
});
html += `</div>`;
container.innerHTML = html;
if (typeof initCardTiltGlow === 'function') initCardTiltGlow();
}
async function loadWordPressPosts() {
const cacheKey = "wp_latest_posts_cache";
const cacheTimeKey = "wp_latest_posts_cache_time";
const cacheExpiry = 60 * 60 * 1000;
try {
const cachedData = localStorage.getItem(cacheKey);
const cachedTime = localStorage.getItem(cacheTimeKey);
if (cachedData && cachedTime) {
const age = Date.now() - parseInt(cachedTime, 10);
if (age < cacheExpiry) {
const posts = JSON.parse(cachedData);
if (posts && posts.length > 0) {
renderPosts(posts);
return;
}
}
}
} catch (e) {
console.warn("Error reading posts cache:", e);
}
try {
const response = await fetch(window.location.origin + "/wp-json/ideas/v1/latest-news");
if (!response.ok) throw new Error("API call failed");
const posts = await response.json();
if (posts && posts.length > 0) {
renderPosts(posts);
try {
localStorage.setItem(cacheKey, JSON.stringify(posts));
localStorage.setItem(cacheTimeKey, Date.now().toString());
} catch (e) {
console.warn("Error saving posts cache:", e);
}
}
} catch (error) {
console.error("Error loading WordPress posts:", error);
try {
const cachedData = localStorage.getItem(cacheKey);
if (cachedData) {
const posts = JSON.parse(cachedData);
if (posts && posts.length > 0) {
renderPosts(posts);
return;
}
}
} catch (e) {}
const isEn = document.documentElement.lang === 'en';
container.innerHTML = `<p style="grid-column: 1/-1; text-align: center; color: #ef4444; font-weight: 500; padding: 40px 0;">${isEn ? 'Failed to load news posts. Please try again later.' : 'Không thể tải tin tức. Vui lòng thử lại sau.'}</p>`;
}
}
loadWordPressPosts();
}
function initCardTiltGlow() {
if (window.innerWidth < 992) return;
const selectors = '.prog-card-new, .activity-card, .video-talk-card, .pain-card-v2, .pain-stat-card, .featured-card';
document.querySelectorAll(selectors).forEach(card => {
if (!card.querySelector('.card-glow')) {
const glow = document.createElement('div');
glow.className = 'card-glow';
card.appendChild(glow);
}
card.style.position = 'relative';
card.style.transformStyle = 'preserve-3d';
const isProgCard = card.classList.contains('prog-card-new');
card.addEventListener('mousemove', e => {
const rect = card.getBoundingClientRect();
const x = e.clientX - rect.left;
const y = e.clientY - rect.top;
card.style.setProperty('--mouse-x', `${x}px`);
card.style.setProperty('--mouse-y', `${y}px`);
if (!isProgCard) {
const centerX = rect.width / 2;
const centerY = rect.height / 2;
const rotateX = ((centerY - y) / centerY) * 3.5;
const rotateY = ((x - centerX) / centerX) * 3.5;
card.style.transform = `perspective(1000px) rotateX(${rotateX}deg) rotateY(${rotateY}deg) scale3d(1.015, 1.015, 1.015)`;
}
});
card.addEventListener('mouseleave', () => {
if (!isProgCard) {
card.style.transform = '';
}
card.style.transition = 'all 0.5s cubic-bezier(0.25, 1, 0.5, 1)';
});
card.addEventListener('mouseenter', () => {
if (!isProgCard) {
card.style.transition = 'none';
}
});
});
}
function initCountersParallax() {
const bgs = document.querySelectorAll('.counters-bg');
if (bgs.length === 0) return;
function updateParallax() {
bgs.forEach(bg => {
const parent = bg.parentElement;
const rect = parent.getBoundingClientRect();
if (rect.top < window.innerHeight && rect.bottom > 0) {
const speed = 0.25;
const viewportCenter = window.innerHeight / 2;
const sectionCenter = rect.top + rect.height / 2;
const yPos = (sectionCenter - viewportCenter) * speed;
bg.style.transform = `translate3d(0, ${yPos}px, 0) scale(1.15)`;
}
});
}
window.addEventListener('scroll', () => {
window.requestAnimationFrame(updateParallax);
}, { passive: true });
updateParallax();
}
