function initCustomDropdowns() {
if (!document.getElementById('custom-select-styles')) {
const style = document.createElement('style');
style.id = 'custom-select-styles';
style.textContent = `
.custom-select-wrapper {
position: relative;
width: 100%;
user-select: none;
}
.custom-select-trigger {
width: 100%;
padding: 12px 16px;
border: 1px solid #e2e8f0;
border-radius: 10px;
font-size: 0.9rem;
font-weight: 500;
color: #1e293b;
background: #f8fafc;
outline: none;
transition: all 0.2s ease;
display: flex;
align-items: center;
justify-content: space-between;
cursor: pointer;
box-sizing: border-box;
height: 46px;
}
.custom-select-wrapper.open .custom-select-trigger {
border-color: #ab0e00;
background: #ffffff;
box-shadow: 0 0 0 3px rgba(171, 14, 0, 0.08);
}
.custom-select-trigger span {
white-space: nowrap;
overflow: hidden;
text-overflow: ellipsis;
margin-right: 8px;
}
.custom-select-trigger i {
font-size: 0.8rem;
color: #64748b;
transition: transform 0.2s ease;
flex-shrink: 0;
}
.custom-select-wrapper.open .custom-select-trigger i {
transform: rotate(180deg);
color: #ab0e00;
}
.custom-select-options {
position: absolute;
top: calc(100% + 8px);
left: 0;
width: 100%;
background: #ffffff;
border: 1px solid #e2e8f0;
border-radius: 16px;
box-shadow: 0 12px 30px rgba(15, 23, 42, 0.08);
z-index: 9999;
opacity: 0;
visibility: hidden;
transform: translateY(10px) scale(0.95);
transition: opacity 0.2s ease, transform 0.2s ease, visibility 0.2s;
max-height: 280px;
overflow-y: auto;
padding: 6px;
box-sizing: border-box;
}
.custom-select-wrapper.open .custom-select-options {
opacity: 1;
visibility: visible;
transform: translateY(0) scale(1);
}
.custom-select-option {
padding: 10px 14px;
font-size: 0.9rem;
color: #334155;
cursor: pointer;
border-radius: 10px;
transition: all 0.15s ease;
white-space: nowrap;
overflow: hidden;
text-overflow: ellipsis;
}
.custom-select-option:hover {
background: #fdf2f2;
color: #ab0e00;
}
.custom-select-option.selected {
background: #ab0e00;
color: #ffffff;
font-weight: 600;
}
.custom-select-option.placeholder-option {
color: #94a3b8;
font-style: italic;
}
.custom-select-option.placeholder-option:hover {
background: #f1f5f9;
color: #475569;
}
`;
document.head.appendChild(style);
}
const selects = document.querySelectorAll(
'.ideas-widget-form select, .ideas-contact-form select, .form-group select, .ideas-booking-form select, .ideas-registration-form select, .sidebar-widget select, .cta-form select'
);
selects.forEach(select => {
if (select.nextElementSibling && select.nextElementSibling.classList.contains('custom-select-wrapper')) {
return;
}
if (select.parentElement.classList.contains('custom-select-wrapper') || select.parentElement.classList.contains('select-wrapper')) {
return;
}
const wrapper = document.createElement('div');
wrapper.className = 'custom-select-wrapper';
const trigger = document.createElement('div');
trigger.className = 'custom-select-trigger';
const selectedOpt = select.querySelector('option[selected]') || select.querySelector('option');
const triggerText = document.createElement('span');
triggerText.textContent = selectedOpt ? selectedOpt.textContent : '-- Chọn --';
if (selectedOpt && !selectedOpt.value) {
triggerText.style.color = '#94a3b8';
}
const triggerIcon = document.createElement('i');
triggerIcon.className = 'fa-solid fa-chevron-down';
trigger.appendChild(triggerText);
trigger.appendChild(triggerIcon);
wrapper.appendChild(trigger);
const optionsContainer = document.createElement('div');
optionsContainer.className = 'custom-select-options';
const options = select.querySelectorAll('option');
options.forEach(opt => {
const optDiv = document.createElement('div');
optDiv.className = 'custom-select-option';
optDiv.textContent = opt.textContent;
optDiv.setAttribute('data-value', opt.value);
if (opt.selected) {
optDiv.classList.add('selected');
}
if (!opt.value) {
optDiv.classList.add('placeholder-option');
}
optDiv.addEventListener('click', (e) => {
e.stopPropagation();
select.value = opt.value;
select.dispatchEvent(new Event('change', { bubbles: true }));
select.dispatchEvent(new Event('input', { bubbles: true }));
optionsContainer.querySelectorAll('.custom-select-option').forEach(o => o.classList.remove('selected'));
optDiv.classList.add('selected');
triggerText.textContent = opt.textContent;
if (!opt.value) {
triggerText.style.color = '#94a3b8';
} else {
triggerText.style.color = '';
}
wrapper.classList.remove('open');
});
optionsContainer.appendChild(optDiv);
});
wrapper.appendChild(optionsContainer);
select.style.display = 'none';
select.parentNode.insertBefore(wrapper, select.nextSibling);
trigger.addEventListener('click', (e) => {
e.stopPropagation();
document.querySelectorAll('.custom-select-wrapper').forEach(w => {
if (w !== wrapper) {
w.classList.remove('open');
}
});
wrapper.classList.toggle('open');
});
});
document.addEventListener('click', () => {
document.querySelectorAll('.custom-select-wrapper').forEach(w => {
w.classList.remove('open');
});
});
}
function initGlobalReelsModal() {
const modal = document.getElementById('fb-reel-modal');
const iframe = document.getElementById('fb-reel-iframe');
const closeBtn = modal ? modal.querySelector('.fb-reel-modal-close') : null;
const overlay = modal ? modal.querySelector('.fb-reel-modal-overlay') : null;
const floatingBtn = document.querySelector('.global-floating-reel-btn');
if (!modal) return;
function openModal(reelId) {
if (!iframe) return;
const embedUrl = 'https://www.youtube.com/embed/' + reelId + '?autoplay=1&mute=0&loop=1&playlist=' + reelId + '&controls=1&rel=0&playsinline=1';
iframe.src = embedUrl;
modal.style.display = 'flex';
setTimeout(() => {
modal.classList.add('open');
}, 10);
const loading = modal.querySelector('.fb-reel-video-loading');
iframe.onload = function() {
if (loading) loading.style.display = 'none';
iframe.style.opacity = '1';
};
document.body.style.overflow = 'hidden';
}
function closeModal() {
modal.classList.remove('open');
setTimeout(() => {
modal.style.display = 'none';
if (iframe) {
iframe.src = '';
iframe.style.opacity = '0';
}
const loading = modal.querySelector('.fb-reel-video-loading');
if (loading) loading.style.display = 'block';
}, 400);
document.body.style.overflow = '';
}
if (closeBtn) closeBtn.addEventListener('click', closeModal);
if (overlay) overlay.addEventListener('click', closeModal);
document.addEventListener('keydown', (e) => {
if (e.key === 'Escape') closeModal();
});
if (floatingBtn) {
const path = window.location.pathname.toLowerCase();
let reelId = '';
if (path.indexOf('sacombank') !== -1) {
reelId = 'tfSh3cVhvR8';
} else if (path.indexOf('bba') !== -1 && path.indexOf('fullbba') === -1) {
reelId = 'YgF77KEghOI';
} else if (path.indexOf('mba') !== -1 || path.indexOf('emba') !== -1 || path.indexOf('dba') !== -1 || path.indexOf('mscai') !== -1 || path.indexOf('mbainai') !== -1 || path.indexOf('tri-tue-song-hanh') !== -1) {
reelId = 'rXWWEC2LJJM';
}
if (reelId) {
floatingBtn.addEventListener('click', (e) => {
e.preventDefault();
openModal(reelId);
});
}
}
}
